INSERT INTO internal.suppliers (supplier_number, company_name, category, tax_id, contact_email, contact_phone, address, city, province, postal_code, country, payment_terms, status) SELECT 'PRV-' || LPAD((COALESCE((SELECT MAX(CAST(SUBSTRING(supplier_number FROM 5) AS INTEGER)) FROM internal.suppliers WHERE supplier_number ~ '^PRV-[0-9]+$'), 0) + 1)::TEXT, 6, '0'), 'PC COMPONENTES Y MULTIMEDIA S.L.U.', 'MATERIAL', 'B73347494', 'soporte.negocios@pccomponentes.com', '+34 968 977 977', 'Avda. Europa, Parcelas 2-5 y 2-6, Polígono Industrial Las Salinas', 'Alhama de Murcia', 'Murcia', '30840', 'España', NULL, 'ACTIVE' FROM (SELECT 1) AS _seed WHERE NOT EXISTS (SELECT 1 FROM internal.suppliers WHERE tax_id = 'B73347494');
